export declare const elasticAgentStandaloneManifest = "---\n# For more information refer https://www.elastic.co/guide/en/fleet/current/running-on-kubernetes-standalone.html\napiVersion: apps/v1\nkind: DaemonSet\nmetadata:\n  name: elastic-agent\n  namespace: kube-system\n  labels:\n    app.kubernetes.io/name: elastic-agent\nspec:\n  selector:\n    matchLabels:\n      app.kubernetes.io/name: elastic-agent\n  template:\n    metadata:\n      labels:\n        app.kubernetes.io/name: elastic-agent\n    spec:\n      # Tolerations are needed to run Elastic Agent on Kubernetes control-plane nodes.\n      # Agents running on control-plane nodes collect metrics from the control plane components (scheduler, controller manager) of Kubernetes\n      tolerations:\n        - key: node-role.kubernetes.io/control-plane\n          effect: NoSchedule\n        - key: node-role.kubernetes.io/master\n          effect: NoSchedule\n      serviceAccountName: elastic-agent\n      # The following setting is needed for Universal Profiling to observe all processes on the host\n      # and produce userspace frames.\n      # If you are using the Universal Profiling integration, please uncomment the following line before applying.\n      # hostPID: true\n      hostNetwork: true\n      dnsPolicy: ClusterFirstWithHostNet\n      # Uncomment if using hints feature\n      #initContainers:\n      #  - name: k8s-templates-downloader\n      #    image: docker.elastic.co/elastic-agent/elastic-agent:VERSION\n      #    command: ['bash']\n      #    args:\n      #      - -c\n      #      - >-\n      #        mkdir -p /etc/elastic-agent/inputs.d &&\n      #        curl -sL https://github.com/elastic/elastic-agent/archive/refs/tags/vVERSION.tar.gz | tar xz -C /etc/elastic-agent/inputs.d --strip=5 \"elastic-agent-VERSION/deploy/kubernetes/elastic-agent-standalone/templates.d\"\n      #    volumeMounts:\n      #      - name: external-inputs\n      #        mountPath: /etc/elastic-agent/inputs.d\n      containers:\n        - name: elastic-agent\n          image: docker.elastic.co/elastic-agent/elastic-agent:VERSION\n          args: [\"-c\", \"/etc/elastic-agent/agent.yml\", \"-e\"]\n          env:\n            # The API Key with access privilleges to connect to Elasticsearch. https://www.elastic.co/guide/en/fleet/current/grant-access-to-elasticsearch.html#create-api-key-standalone-agent\n            - name: API_KEY\n            # The basic authentication username used to connect to Elasticsearch. Alternative to API_KEY access.\n            # This user needs the privileges required to publish events to Elasticsearch.\n            - name: ES_USERNAME\n              value: \"elastic\"\n            # The basic authentication password used to connect to Elasticsearch\n            - name: ES_PASSWORD\n              value: \"changeme\"\n            # The fingerprint of a root CA certificate used to sign\n            # Elasticsearch's TLS certificate\n            - name: CA_TRUSTED\n            - name: NODE_NAME\n              valueFrom:\n                fieldRef:\n                  fieldPath: spec.nodeName\n            - name: POD_NAME\n              valueFrom:\n                fieldRef:\n                  fieldPath: metadata.name\n            # The following ELASTIC_NETINFO:false variable will disable the netinfo.enabled option of add-host-metadata processor. This will remove fields host.ip and host.mac.\n            # For more info: https://www.elastic.co/guide/en/beats/metricbeat/current/add-host-metadata.html\n            - name: ELASTIC_NETINFO\n              value: \"false\"\n            # 'Defend for containers' integration (cloud-defend) uses the HOSTFS_PROC_PATH variable for accessing process information from the node.\n            - name: HOSTFS_PROC_PATH\n              value: \"/hostfs/proc\"\n          securityContext:\n            runAsUser: 0\n            # The following capabilities are needed for 'Defend for containers' integration (cloud-defend)\n            # If you are using this integration, please uncomment these lines before applying.\n            #capabilities:\n            #  add:\n            #    - BPF # (since Linux 5.8) allows loading of BPF programs, create most map types, load BTF, iterate programs and maps.\n            #    - PERFMON # (since Linux 5.8) allows attaching of BPF programs used for performance metrics and observability operations.\n            #    - SYS_RESOURCE # Allow use of special resources or raising of resource limits. Used by 'Defend for Containers' to modify 'rlimit_memlock'\n            ########################################################################################\n            # The following capabilities are needed for Universal Profiling.\n            # More fine graded capabilities are only available for newer Linux kernels.\n            # If you are using the Universal Profiling integration, please uncomment these lines before applying.\n            #privileged: true\n            #capabilities:\n            #  add:\n            #    - SYS_ADMIN\n          resources:\n            limits:\n              memory: 1200Mi\n            requests:\n              cpu: 100m\n              memory: 500Mi\n          volumeMounts:\n            - name: datastreams\n              mountPath: /etc/elastic-agent/agent.yml\n              readOnly: true\n              subPath: agent.yml\n            - name: proc\n              mountPath: /hostfs/proc\n              readOnly: true\n            - name: cgroup\n              mountPath: /hostfs/sys/fs/cgroup\n              readOnly: true\n            - name: varlibdockercontainers\n              mountPath: /var/lib/docker/containers\n              readOnly: true\n            - name: varlog\n              mountPath: /var/log\n              readOnly: true\n            - name: etc-full\n              mountPath: /hostfs/etc\n              readOnly: true\n            - name: var-lib\n              mountPath: /hostfs/var/lib\n              readOnly: true\n            - name: sys-kernel-debug\n              mountPath: /sys/kernel/debug\n            - name: boot\n              mountPath: /boot\n              readOnly: true\n            - name: sys-fs-bpf\n              mountPath: /sys/fs/bpf\n            - name: sys-kernel-security\n              mountPath: /sys/kernel/security\n              readOnly: true\n            - name: elastic-agent-state\n              mountPath: /usr/share/elastic-agent/state\n            # Uncomment if using hints feature\n            # - name: external-inputs\n            #   mountPath: /usr/share/elastic-agent/state/inputs.d\n      volumes:\n        - name: datastreams\n          configMap:\n            defaultMode: 0644\n            name: agent-node-datastreams\n        - name: proc\n          hostPath:\n            path: /proc\n        - name: cgroup\n          hostPath:\n            path: /sys/fs/cgroup\n        - name: varlibdockercontainers\n          hostPath:\n            path: /var/lib/docker/containers\n        - name: varlog\n          hostPath:\n            path: /var/log\n        # The following volumes are needed for Cloud Security Posture integration (cloudbeat)\n        # If you are not using this integration, then these volumes and the corresponding\n        # mounts can be removed.\n        - name: etc-full\n          hostPath:\n            path: /etc\n        - name: var-lib\n          hostPath:\n            path: /var/lib\n        # Needed for 'Defend for containers' integration (cloud-defend) and Universal Profiling\n        # If you are not using one of these integrations, then these volumes and the corresponding\n        # mounts can be removed.\n        - name: sys-kernel-debug\n          hostPath:\n            path: /sys/kernel/debug\n        # The following three mounts are needed for 'Defend for containers' integration (cloud-defend)\n        # If you are not using cloud-defend, then these volumes and the corresponding mounts can be removed.\n        - name: boot\n          hostPath:\n            path: /boot\n        - name: sys-fs-bpf\n          hostPath:\n            path: /sys/fs/bpf\n        - name: sys-kernel-security\n          hostPath:\n            path: /sys/kernel/security\n        # Mount /var/lib/elastic-agent-managed/kube-system/state to store elastic-agent state\n        # Update 'kube-system' with the namespace of your agent installation\n        - name: elastic-agent-state\n          hostPath:\n            path: /var/lib/elastic-agent/kube-system/state\n            type: DirectoryOrCreate\n        # Uncomment if using hints feature\n        # - name: external-inputs\n        #   emptyDir: {}\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: ClusterRoleBinding\nmetadata:\n  name: elastic-agent\nsubjects:\n  - kind: ServiceAccount\n    name: elastic-agent\n    namespace: kube-system\nroleRef:\n  kind: ClusterRole\n  name: elastic-agent\n  apiGroup: rbac.authorization.k8s.io\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: RoleBinding\nmetadata:\n  namespace: kube-system\n  name: elastic-agent\nsubjects:\n  - kind: ServiceAccount\n    name: elastic-agent\n    namespace: kube-system\nroleRef:\n  kind: Role\n  name: elastic-agent\n  apiGroup: rbac.authorization.k8s.io\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: RoleBinding\nmetadata:\n  name: elastic-agent-kubeadm-config\n  namespace: kube-system\nsubjects:\n  - kind: ServiceAccount\n    name: elastic-agent\n    namespace: kube-system\nroleRef:\n  kind: Role\n  name: elastic-agent-kubeadm-config\n  apiGroup: rbac.authorization.k8s.io\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: ClusterRole\nmetadata:\n  name: elastic-agent\n  labels:\n    app.kubernetes.io/name: elastic-agent\nrules:\n  - apiGroups: [\"\"]\n    resources:\n      - nodes\n      - namespaces\n      - events\n      - pods\n      - services\n      - configmaps\n      # Needed for cloudbeat\n      - serviceaccounts\n      - persistentvolumes\n      - persistentvolumeclaims\n    verbs: [\"get\", \"list\", \"watch\"]\n  # Enable this rule only if planing to use kubernetes_secrets provider\n  #- apiGroups: [\"\"]\n  #  resources:\n  #  - secrets\n  #  verbs: [\"get\"]\n  - apiGroups: [\"extensions\"]\n    resources:\n      - replicasets\n    verbs: [\"get\", \"list\", \"watch\"]\n  - apiGroups: [\"apps\"]\n    resources:\n      - statefulsets\n      - deployments\n      - replicasets\n      - daemonsets\n    verbs: [\"get\", \"list\", \"watch\"]\n  - apiGroups: [\"batch\"]\n    resources:\n      - jobs\n      - cronjobs\n    verbs: [\"get\", \"list\", \"watch\"]\n  - apiGroups:\n      - \"\"\n    resources:\n      - nodes/stats\n    verbs:\n      - get\n  # Needed for apiserver\n  - nonResourceURLs:\n      - \"/metrics\"\n    verbs:\n      - get\n  # Needed for cloudbeat\n  - apiGroups: [\"rbac.authorization.k8s.io\"]\n    resources:\n      - clusterrolebindings\n      - clusterroles\n      - rolebindings\n      - roles\n    verbs: [\"get\", \"list\", \"watch\"]\n  # Needed for cloudbeat\n  - apiGroups: [\"policy\"]\n    resources:\n      - podsecuritypolicies\n    verbs: [\"get\", \"list\", \"watch\"]\n  - apiGroups: [ \"storage.k8s.io\" ]\n    resources:\n      - storageclasses\n    verbs: [ \"get\", \"list\", \"watch\" ]\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: Role\nmetadata:\n  name: elastic-agent\n  # Should be the namespace where elastic-agent is running\n  namespace: kube-system\n  labels:\n    app.kubernetes.io/name: elastic-agent\nrules:\n  - apiGroups:\n      - coordination.k8s.io\n    resources:\n      - leases\n    verbs: [\"get\", \"create\", \"update\"]\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: Role\nmetadata:\n  name: elastic-agent-kubeadm-config\n  namespace: kube-system\n  labels:\n    app.kubernetes.io/name: elastic-agent\nrules:\n  - apiGroups: [\"\"]\n    resources:\n      - configmaps\n    resourceNames:\n      - kubeadm-config\n    verbs: [\"get\"]\n---\napiVersion: v1\nkind: ServiceAccount\nmetadata:\n  name: elastic-agent\n  namespace: kube-system\n  labels:\n    app.kubernetes.io/name: elastic-agent\n---\n";
export declare const elasticAgentManagedManifest = "---\n# For more information https://www.elastic.co/guide/en/fleet/current/running-on-kubernetes-managed-by-fleet.html\napiVersion: apps/v1\nkind: DaemonSet\nmetadata:\n  name: elastic-agent\n  namespace: kube-system\n  labels:\n    app.kubernetes.io/name: elastic-agent\nspec:\n  selector:\n    matchLabels:\n      app.kubernetes.io/name: elastic-agent\n  template:\n    metadata:\n      labels:\n        app.kubernetes.io/name: elastic-agent\n    spec:\n      # Tolerations are needed to run Elastic Agent on Kubernetes control-plane nodes.\n      # Agents running on control-plane nodes collect metrics from the control plane components (scheduler, controller manager) of Kubernetes\n      tolerations:\n        - key: node-role.kubernetes.io/control-plane\n          effect: NoSchedule\n        - key: node-role.kubernetes.io/master\n          effect: NoSchedule\n      serviceAccountName: elastic-agent\n      # The following setting is needed for Universal Profiling to observe all processes on the host\n      # and produce userspace frames.\n      # If you are using the Universal Profiling integration, please uncomment the following line before applying.\n      # hostPID: true\n      hostNetwork: true\n      dnsPolicy: ClusterFirstWithHostNet\n      containers:\n        - name: elastic-agent\n          image: docker.elastic.co/elastic-agent/elastic-agent:VERSION\n          env:\n            # Set to 1 for enrollment into Fleet server. If not set, Elastic Agent is run in standalone mode\n            - name: FLEET_ENROLL\n              value: \"1\"\n            # Set to true to communicate with Fleet with either insecure HTTP or unverified HTTPS\n            - name: FLEET_INSECURE\n              value: \"false\"\n            # Fleet Server URL to enroll the Elastic Agent into\n            # FLEET_URL can be found in Kibana, go to Management > Fleet > Settings\n            - name: FLEET_URL\n              value: \"https://fleet-server:8220\"\n            # Elasticsearch API key used to enroll Elastic Agents in Fleet (https://www.elastic.co/guide/en/fleet/current/fleet-enrollment-tokens.html#fleet-enrollment-tokens)\n            # If FLEET_ENROLLMENT_TOKEN is empty then KIBANA_HOST, KIBANA_FLEET_USERNAME, KIBANA_FLEET_PASSWORD are needed\n            - name: FLEET_ENROLLMENT_TOKEN\n              value: \"token-id\"\n            - name: KIBANA_HOST\n              value: \"http://kibana:5601\"\n            # The basic authentication username used to connect to Kibana and retrieve a service_token to enable Fleet\n            - name: KIBANA_FLEET_USERNAME\n              value: \"elastic\"\n            # The basic authentication password used to connect to Kibana and retrieve a service_token to enable Fleet\n            - name: KIBANA_FLEET_PASSWORD\n              value: \"changeme\"\n            - name: NODE_NAME\n              valueFrom:\n                fieldRef:\n                  fieldPath: spec.nodeName\n            - name: POD_NAME\n              valueFrom:\n                fieldRef:\n                  fieldPath: metadata.name\n            # The following ELASTIC_NETINFO:false variable will disable the netinfo.enabled option of add-host-metadata processor. This will remove fields host.ip and host.mac.\n            # For more info: https://www.elastic.co/guide/en/beats/metricbeat/current/add-host-metadata.html\n            - name: ELASTIC_NETINFO\n              value: \"false\"\n            # 'Defend for containers' integration (cloud-defend) uses the HOSTFS_PROC_PATH variable for accessing process information from the node.\n            - name: HOSTFS_PROC_PATH\n              value: \"/hostfs/proc\"\n          securityContext:\n            runAsUser: 0\n            # The following capabilities are needed for 'Defend for containers' integration (cloud-defend)\n            # If you are using this integration, please uncomment these lines before applying.\n            #capabilities:\n            #  add:\n            #    - BPF # (since Linux 5.8) allows loading of BPF programs, create most map types, load BTF, iterate programs and maps.\n            #    - PERFMON # (since Linux 5.8) allows attaching of BPF programs used for performance metrics and observability operations.\n            #    - SYS_RESOURCE # Allow use of special resources or raising of resource limits. Used by 'Defend for Containers' to modify 'rlimit_memlock'\n            ########################################################################################\n            # The following capabilities are needed for Universal Profiling.\n            # More fine graded capabilities are only available for newer Linux kernels.\n            # If you are using the Universal Profiling integration, please uncomment these lines before applying.\n            #privileged: true\n            #capabilities:\n            #  add:\n            #    - SYS_ADMIN\n          resources:\n            limits:\n              memory: 1200Mi\n            requests:\n              cpu: 100m\n              memory: 500Mi\n          volumeMounts:\n            - name: proc\n              mountPath: /hostfs/proc\n              readOnly: true\n            - name: cgroup\n              mountPath: /hostfs/sys/fs/cgroup\n              readOnly: true\n            - name: varlibdockercontainers\n              mountPath: /var/lib/docker/containers\n              readOnly: true\n            - name: varlog\n              mountPath: /var/log\n              readOnly: true\n            - name: etc-full\n              mountPath: /hostfs/etc\n              readOnly: true\n            - name: var-lib\n              mountPath: /hostfs/var/lib\n              readOnly: true\n            - name: etc-mid\n              mountPath: /etc/machine-id\n              readOnly: true\n            - name: sys-kernel-debug\n              mountPath: /sys/kernel/debug\n            - name: boot\n              mountPath: /boot\n              readOnly: true\n            - name: sys-fs-bpf\n              mountPath: /sys/fs/bpf\n            - name: sys-kernel-security\n              mountPath: /sys/kernel/security\n              readOnly: true\n            - name: elastic-agent-state\n              mountPath: /usr/share/elastic-agent/state\n      volumes:\n        - name: proc\n          hostPath:\n            path: /proc\n        - name: cgroup\n          hostPath:\n            path: /sys/fs/cgroup\n        - name: varlibdockercontainers\n          hostPath:\n            path: /var/lib/docker/containers\n        - name: varlog\n          hostPath:\n            path: /var/log\n        # The following volumes are needed for Cloud Security Posture integration (cloudbeat)\n        # If you are not using this integration, then these volumes and the corresponding\n        # mounts can be removed.\n        - name: etc-full\n          hostPath:\n            path: /etc\n        - name: var-lib\n          hostPath:\n            path: /var/lib\n        # Mount /etc/machine-id from the host to determine host ID\n        # Needed for Kubernetes node autodiscovery\n        - name: etc-mid\n          hostPath:\n            path: /etc/machine-id\n            type: File\n        # Needed for 'Defend for containers' integration (cloud-defend) and Universal Profiling\n        # If you are not using one of these integrations, then these volumes and the corresponding\n        # mounts can be removed.\n        - name: sys-kernel-debug\n          hostPath:\n            path: /sys/kernel/debug\n        # The following three mounts are needed for 'Defend for containers' integration (cloud-defend)\n        # If you are not using cloud-defend, then these volumes and the corresponding mounts can be removed.\n        - name: boot\n          hostPath:\n            path: /boot\n        - name: sys-fs-bpf\n          hostPath:\n            path: /sys/fs/bpf\n        - name: sys-kernel-security\n          hostPath:\n            path: /sys/kernel/security\n        # Mount /var/lib/elastic-agent-managed/kube-system/state to store elastic-agent state\n        # Update 'kube-system' with the namespace of your agent installation\n        - name: elastic-agent-state\n          hostPath:\n            path: /var/lib/elastic-agent-managed/kube-system/state\n            type: DirectoryOrCreate\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: ClusterRoleBinding\nmetadata:\n  name: elastic-agent\nsubjects:\n  - kind: ServiceAccount\n    name: elastic-agent\n    namespace: kube-system\nroleRef:\n  kind: ClusterRole\n  name: elastic-agent\n  apiGroup: rbac.authorization.k8s.io\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: RoleBinding\nmetadata:\n  namespace: kube-system\n  name: elastic-agent\nsubjects:\n  - kind: ServiceAccount\n    name: elastic-agent\n    namespace: kube-system\nroleRef:\n  kind: Role\n  name: elastic-agent\n  apiGroup: rbac.authorization.k8s.io\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: RoleBinding\nmetadata:\n  name: elastic-agent-kubeadm-config\n  namespace: kube-system\nsubjects:\n  - kind: ServiceAccount\n    name: elastic-agent\n    namespace: kube-system\nroleRef:\n  kind: Role\n  name: elastic-agent-kubeadm-config\n  apiGroup: rbac.authorization.k8s.io\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: ClusterRole\nmetadata:\n  name: elastic-agent\n  labels:\n    app.kubernetes.io/name: elastic-agent\nrules:\n  - apiGroups: [\"\"]\n    resources:\n      - nodes\n      - namespaces\n      - events\n      - pods\n      - services\n      - configmaps\n      # Needed for cloudbeat\n      - serviceaccounts\n      - persistentvolumes\n      - persistentvolumeclaims\n    verbs: [\"get\", \"list\", \"watch\"]\n  # Enable this rule only if planing to use kubernetes_secrets provider\n  #- apiGroups: [\"\"]\n  #  resources:\n  #  - secrets\n  #  verbs: [\"get\"]\n  - apiGroups: [\"extensions\"]\n    resources:\n      - replicasets\n    verbs: [\"get\", \"list\", \"watch\"]\n  - apiGroups: [\"apps\"]\n    resources:\n      - statefulsets\n      - deployments\n      - replicasets\n      - daemonsets\n    verbs: [\"get\", \"list\", \"watch\"]\n  - apiGroups:\n      - \"\"\n    resources:\n      - nodes/stats\n    verbs:\n      - get\n  - apiGroups: [ \"batch\" ]\n    resources:\n      - jobs\n      - cronjobs\n    verbs: [ \"get\", \"list\", \"watch\" ]\n  # Needed for apiserver\n  - nonResourceURLs:\n      - \"/metrics\"\n    verbs:\n      - get\n  # Needed for cloudbeat\n  - apiGroups: [\"rbac.authorization.k8s.io\"]\n    resources:\n      - clusterrolebindings\n      - clusterroles\n      - rolebindings\n      - roles\n    verbs: [\"get\", \"list\", \"watch\"]\n  # Needed for cloudbeat\n  - apiGroups: [\"policy\"]\n    resources:\n      - podsecuritypolicies\n    verbs: [\"get\", \"list\", \"watch\"]\n  - apiGroups: [ \"storage.k8s.io\" ]\n    resources:\n      - storageclasses\n    verbs: [ \"get\", \"list\", \"watch\" ]\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: Role\nmetadata:\n  name: elastic-agent\n  # Should be the namespace where elastic-agent is running\n  namespace: kube-system\n  labels:\n    app.kubernetes.io/name: elastic-agent\nrules:\n  - apiGroups:\n      - coordination.k8s.io\n    resources:\n      - leases\n    verbs: [\"get\", \"create\", \"update\"]\n---\napiVersion: rbac.authorization.k8s.io/v1\nkind: Role\nmetadata:\n  name: elastic-agent-kubeadm-config\n  namespace: kube-system\n  labels:\n    app.kubernetes.io/name: elastic-agent\nrules:\n  - apiGroups: [\"\"]\n    resources:\n      - configmaps\n    resourceNames:\n      - kubeadm-config\n    verbs: [\"get\"]\n---\napiVersion: v1\nkind: ServiceAccount\nmetadata:\n  name: elastic-agent\n  namespace: kube-system\n  labels:\n    app.kubernetes.io/name: elastic-agent\n---\n";
